/*
 * psmgr_core.c - Protocol Session Manager: payload processing path
 *
 * Consumer of session state. Implements a processing pipeline governed by
 * desc->write_count as a write completion counter. Each in-bounds DATA
 * write increments write_count by one. When write_count reaches
 * PSMGR_BUF_WRITE_THRESH the buffer is considered complete and the
 * kernel installs token. COMMIT_REQ is accepted only after completion.
 * The exec path is gated on PSMGR_BUF_COMMITTED, token non-zero, and
 * handler non-null.
 *
 * Sequence numbers are validated on all message types except PROBE.
 * CTRL messages carry subtypes that affect session state. PROBE messages
 * update keepalive state. RESPONDER window updates are applied to session ctx.
 */

