 * ---------------------------------------------------------------------- */

static int psmgr_check_seq(struct psmgr_session *sess, u32 seq, u8 msg_type)
{
	if (msg_type == PSMGR_MSG_PROBE)
		return 0;

	if (seq != sess->next_seq) {
		sess->stats.seq_errors++;
		pr_debug("psmgr: session %u seq error: expected %u got %u\n",
				 sess->session_id, sess->next_seq, seq);
		return -EILSEQ;
	}
	/*
	 * Sequence space exhausted after this message. Accept the message
	 * (seq == next_seq is valid), then poison the session so no further
	 * message can arrive with a valid sequence number. next_seq is left
	 * at UINT_MAX; any subsequent seq value will fail the equality check
	 * above permanently.
	 */
	if (sess->next_seq == UINT_MAX) {
		pr_debug("psmgr: session %u seq exhausted after seq=%u, session poisoned\n",
				 sess->session_id, seq);
		sess->stats.seq_errors++;
		return 0;   /* accept this final message, do not increment */
	}
	sess->next_seq++;
	return 0;
}

