/*
 * af_psmgr.c - Protocol Session Manager: module entry point
 *
 * Registers AF_PSMGR as a SOCK_SEQPACKET address family. Manages
 * per-namespace session tables via pernet_operations and exposes
 * session state through /proc/net/psmgr_table.
 */

#include <linux/kernel.h>
#include <linux/module.h>
#include <linux/init.h>
