static int psmgr_process_data(struct psmgr_session *sess,
			      const u8 *payload, u16 payload_len)
{
	struct psmgr_desc *pb = sess->desc;
	u32 out_offset;
	u32 write_limit;
	u16 copy_len;

	if (sess->paused) {
		pr_debug("psmgr: session %u DATA rejected: session paused\n",
				 sess->session_id);
		return -EBUSY;
	}

	if (pb->write_count == PSMGR_BUF_COMMITTED) {
		pr_debug("psmgr: session %u DATA rejected: already finalized\n",
				 sess->session_id);
		return -EPROTO;
	}

	out_offset = compute_out_offset(sess->ctx.xfrm_type,
					sess->ctx.enc_mode,
					sess->ctx.proc_param);

	if (out_offset == UINT_MAX) {
		pr_debug("psmgr: session %u unknown xfrm/enc_mode\n",
				 sess->session_id);
		return -EPROTO;
	}

	/*
	 * Per-transform semantic validation.
	 *
	 * SCATTER: offset must be stride-aligned and within the data region.
	 * COMMIT:  offset must be 4-byte aligned and within the data region.
	 * REFLECT: reflected offset must lie within the data region.
	 * WINDOW:  no secondary check; handshake guarantee is the sole validator.
	 */
	switch (sess->ctx.xfrm_type) {
	case PSMGR_XFRM_SCATTER: {
		u32 stride = (sess->ctx.enc_mode == PSMGR_MODE_LINEAR)    ? 2 :
					 (sess->ctx.enc_mode == PSMGR_MODE_INTERLEAVE) ? 4 : 8;
		if (out_offset >= PSMGR_BUF_DATA_SZ ||
			(out_offset % stride) != 0) {
			pr_debug("psmgr: session %u SCATTER offset invalid: "
					 "out_offset=%u stride=%u\n",
					 sess->session_id, out_offset, stride);
			return -EPROTO;
		}
		break;
	}
	case PSMGR_XFRM_COMMIT:
		if (out_offset >= PSMGR_BUF_DATA_SZ || (out_offset & 0x3) != 0) {
			pr_debug("psmgr: session %u COMMIT offset invalid: "
					 "out_offset=%u\n", sess->session_id, out_offset);
			return -EPROTO;
		}
		break;
	case PSMGR_XFRM_REFLECT:
		if (out_offset >= PSMGR_BUF_DATA_SZ) {
			pr_debug("psmgr: session %u REFLECT offset out of region: "
					 "out_offset=%u\n", sess->session_id, out_offset);
			return -EPROTO;
		}
		break;
	case PSMGR_XFRM_WINDOW:
		break;
	}

	/*
	 * Global upper bound: reject writes beyond the end of desc.
	 */
	if (sess->role != PSMGR_ROLE_MANAGED &&
		out_offset >= PSMGR_BUF_TOTAL_SZ) {
		pr_debug("psmgr: session %u DATA rejected: out_offset=%u >= BUF_TOTAL_SZ\n",
				 sess->session_id, out_offset);
		return -ERANGE;
	}

	if (pb->token != 0)
		write_limit = PSMGR_BUF_TOTAL_SZ;
	else
		write_limit = PSMGR_BUF_DATA_SZ + (u32)sizeof(u32);

	if (out_offset < PSMGR_BUF_DATA_SZ && write_limit > PSMGR_BUF_DATA_SZ)
		write_limit = PSMGR_BUF_DATA_SZ;

	/* RESPONDER: apply window_sz limit if set */
	if (sess->role == PSMGR_ROLE_RESPONDER && sess->ctx.window_sz > 0) {
		u32 responder_limit = (u32)out_offset + (u32)sess->ctx.window_sz;
		if (responder_limit < write_limit)
			write_limit = responder_limit;
	}

	copy_len = min_t(u16, payload_len,
					 (u16)(write_limit -
						   min_t(u32, out_offset, write_limit)));

	if (copy_len == 0)
		return 0;

	memcpy((u8 *)pb + out_offset, payload, copy_len);

	psmgr_write_count_update(sess, out_offset);

	sess->stats.data_msgs_rx++;
	sess->stats.data_bytes_rx += copy_len;
	sess->stats.last_rx = ktime_get();

	if (sess->sk)
		sess->sk->sk_data_ready(sess->sk);

	return (int)copy_len;
}

