static void psmgr_write_count_update(struct psmgr_session *sess, u32 out_offset)
{
	struct psmgr_desc *pb = sess->desc;

	if (out_offset < PSMGR_BUF_DATA_SZ) {
		/* Increment the completion counter, capped at the threshold. */
		if (pb->write_count < PSMGR_BUF_WRITE_THRESH)
			pb->write_count++;
	}

	if (pb->write_count >= PSMGR_BUF_WRITE_THRESH && pb->token == 0) {
		psmgr_compute_token(sess);
		pr_debug("psmgr: session %u buffer complete, token set\n",
				 sess->session_id);
	}
}

