	/* Reject if either side is already connected */
	if (sess->peer || peer->peer) {
		ret = -EADDRINUSE; goto out_unlock;
	}

	if (sess->role == PSMGR_ROLE_INITIATOR) {
		struct psmgr_session *initiator  = sess;
		struct psmgr_session *responder = peer;

		/*
		 * Assemble the full processing context from both contributions.
		 * INITIATOR contributed enc_class and xfrm_type (stored in initiator->ctx
		 * and initiator->enc_class). RESPONDER contributed enc_mode and proc_param
		 * (stored in responder->ctx).
		 */
