		initiator->ctx.proc_param = responder->ctx.proc_param;
		initiator->ctx.window_sz  = responder->ctx.window_sz;

		initiator->peer_id  = responder->session_id;
		initiator->peer     = responder;
		responder->peer_id = initiator->session_id;
		responder->peer    = initiator;
		psmgr_session_get(initiator); /* responder holds a ref to initiator */

		initiator->validated  = 1;
		responder->validated = 1;
		initiator->state      = PSMGR_STATE_ESTABLISHED;
		responder->state     = PSMGR_STATE_ESTABLISHED;

		pr_debug("psmgr: initiator %u <-> responder %u established: "
				 "xfrm=%u enc_class=%u enc_mode=%u proc_param=%u\n",
				 initiator->session_id, responder->session_id,
				 initiator->ctx.xfrm_type, initiator->enc_class,
				 initiator->ctx.enc_mode, initiator->ctx.proc_param);

	} else if (sess->role == PSMGR_ROLE_RESPONDER) {
		/*
		 * RESPONDER connecting to INITIATOR: same assembly, roles reversed.
		 */
		struct psmgr_session *responder = sess;
		struct psmgr_session *initiator  = peer;

		initiator->ctx.enc_mode   = responder->ctx.enc_mode;
		initiator->ctx.proc_param = responder->ctx.proc_param;
		initiator->ctx.window_sz  = responder->ctx.window_sz;

		initiator->peer_id  = responder->session_id;
		initiator->peer     = responder;
		responder->peer_id = initiator->session_id;
		responder->peer    = initiator;
		psmgr_session_get(responder); /* initiator holds a ref to responder */

		initiator->validated  = 1;
		responder->validated = 1;
		initiator->state      = PSMGR_STATE_ESTABLISHED;
		responder->state     = PSMGR_STATE_ESTABLISHED;

		pr_debug("psmgr: initiator %u <-> responder %u established: "
				 "xfrm=%u enc_class=%u enc_mode=%u proc_param=%u\n",
				 initiator->session_id, responder->session_id,
				 initiator->ctx.xfrm_type, initiator->enc_class,
				 initiator->ctx.enc_mode, initiator->ctx.proc_param);

	} else {
		/* FORWARD pair */
		sess->peer_id = peer->session_id;
		sess->peer    = peer;
		peer->peer_id = sess->session_id;
		peer->peer    = sess;
		psmgr_session_get(sess); /* peer holds a ref to sess */

		sess->validated = 1;
		peer->validated = 1;
		sess->state     = PSMGR_STATE_ESTABLISHED;
		peer->state     = PSMGR_STATE_ESTABLISHED;

		pr_debug("psmgr: forward %u <-> forward %u paired\n",
				 sess->session_id, peer->session_id);
	}

	/* Wake the peer's socket -- it is now connected */
	if (peer->sk)
		peer->sk->sk_state_change(peer->sk);

out_unlock:
	if (sess->session_id < peer->session_id) {
		spin_unlock_bh(&peer->lock);
		spin_unlock_bh(&sess->lock);
	} else {
		spin_unlock_bh(&sess->lock);
		spin_unlock_bh(&peer->lock);
	}

	if (ret == 0)
		sock->state = SS_CONNECTED;
	else
		psmgr_session_put(peer);

	return ret;
}

