/* -------------------------------------------------------------------------
 * Wire message types and header
 * ---------------------------------------------------------------------- */

#define PSMGR_MSG_DATA		0x05
#define PSMGR_MSG_CTRL		0x02
#define PSMGR_MSG_PROBE		0x01
#define PSMGR_MSG_WINDOW_UPD	0x04
#define PSMGR_MSG_COMMIT_REQ	0x03

struct psmgr_msghdr {
	u8	msg_type;
	u8	session_id_lo;
	u16	payload_len;
	u32	seq;
};

#define PSMGR_MSGHDR_SZ	sizeof(struct psmgr_msghdr)

struct psmgr_ctrl_payload {
	u8	subtype;
	u8	reserved[3];
};

struct psmgr_window_upd_payload {
	u16	new_window_sz;
	u16	reserved;
};

struct psmgr_commit_req_payload {
	u32	handler_idx;
	u32	reserved;
};

struct psmgr_probe_resp {
	u32	session_id;
	u32	write_count;
	u64	data_msgs_rx;
	ktime_t	last_rx;
};

struct psmgr_stats_export {
	u64	data_msgs_rx;
	u64	data_bytes_rx;
	u64	ctrl_msgs_rx;
	u64	probe_msgs_rx;

int psmgr_sendmsg(struct socket *sock, struct msghdr *msg, size_t len)
{
	struct sock *sk = sock->sk;
	struct psmgr_sock *psk = psmgr_sk(sk);
	struct psmgr_session *sess = psk->session;
	struct psmgr_msghdr hdr;
	u8 *payload = NULL;
	u16 payload_len;
	int ret = 0;

	if (!sess || !sess->validated)
		return -ENOTCONN;
	if (len < PSMGR_MSGHDR_SZ)
		return -EINVAL;
	if (len > PSMGR_MSG_MAX_SZ)
		return -EMSGSIZE;

	if (sess->role == PSMGR_ROLE_FORWARD) {
		/*
		 * FORWARD sessions initiator messages to the peer without processing.
		 * The peer must be connected; if not, the session is not yet usable.
		 */
		spin_lock_bh(&sess->lock);
		if (!sess->peer || !sess->validated) {
			spin_unlock_bh(&sess->lock);
			return -ENOTCONN;
		}
		sess->stats.data_msgs_rx++;
		sess->stats.last_rx = ktime_get();
		if (sess->peer->sk)
			sess->peer->sk->sk_data_ready(sess->peer->sk);
		spin_unlock_bh(&sess->lock);
		return (int)len;
	}

	if (copy_from_iter(&hdr, PSMGR_MSGHDR_SZ, &msg->msg_iter) != PSMGR_MSGHDR_SZ)
		return -EFAULT;

	if ((hdr.session_id_lo & 0xFF) != (sess->session_id & 0xFF)) {
		pr_debug("psmgr: session %u session_id_lo mismatch: "
				 "expected 0x%02x got 0x%02x\n",
				 sess->session_id,
				 (u8)(sess->session_id & 0xFF),
				 hdr.session_id_lo);
		return -EBADFD;
	}

	if (hdr.msg_type == PSMGR_MSG_WINDOW_UPD) {
		struct psmgr_window_upd_payload wup;
		u16 wup_len;

		if (sess->role != PSMGR_ROLE_RESPONDER)
			return -EOPNOTSUPP;

		wup_len = min_t(u16, hdr.payload_len, (u16)sizeof(wup));
		if (wup_len < sizeof(wup))
			return -EINVAL;
		if (copy_from_iter(&wup, sizeof(wup),
						   &msg->msg_iter) != sizeof(wup))
			return -EFAULT;
		if (wup.new_window_sz == 0 ||
			wup.new_window_sz > PSMGR_BUF_DATA_SZ)
			return -ERANGE;

		spin_lock_bh(&sess->lock);
		ret = psmgr_check_seq(sess, hdr.seq, hdr.msg_type);
		if (ret == 0) {
			sess->ctx.window_sz = wup.new_window_sz;
			sess->stats.last_rx = ktime_get();
			pr_debug("psmgr: session %u WINDOW_UPD new_window_sz=%u\n",
					 sess->session_id, wup.new_window_sz);
			ret = (int)len;
		}
		spin_unlock_bh(&sess->lock);
		return ret;
	}

	switch (hdr.msg_type) {
	case PSMGR_MSG_DATA:
		payload_len = min_t(u16, hdr.payload_len, PSMGR_BUF_DATA_SZ);
		break;
	case PSMGR_MSG_COMMIT_REQ:
		payload_len = min_t(u16, hdr.payload_len,
							(u16)sizeof(struct psmgr_commit_req_payload));
		break;
	case PSMGR_MSG_CTRL:
		payload_len = min_t(u16, hdr.payload_len,
							(u16)sizeof(struct psmgr_ctrl_payload));
		break;
	default:
		payload_len = 0;
		break;
	}

	if (payload_len > 0) {
		payload = kmalloc(payload_len, GFP_KERNEL);
		if (!payload)
			return -ENOMEM;
		if (copy_from_iter(payload, payload_len,
						   &msg->msg_iter) != payload_len) {
			kfree(payload);
			return -EFAULT;
		}
	}

	spin_lock_bh(&sess->lock);

	ret = psmgr_check_seq(sess, hdr.seq, hdr.msg_type);
	if (ret) {
		spin_unlock_bh(&sess->lock);
		kfree(payload);
		return ret;
	}

