int psmgr_recvmsg(struct socket *sock, struct msghdr *msg, size_t len,
		  int flags)
{
	struct sock *sk = sock->sk;
	struct psmgr_sock *psk = psmgr_sk(sk);
	struct psmgr_session *sess = psk->session;
	struct psmgr_desc_export exp;

	if (!sess || !sess->validated)
		return -ENOTCONN;

	if (len < sizeof(exp))
		return -EINVAL;

	memset(&exp, 0, sizeof(exp));
	spin_lock_bh(&sess->lock);
	memcpy(exp.data, sess->desc->data, PSMGR_BUF_DATA_SZ);
	exp.write_count  = sess->desc->write_count;
	exp.token  = sess->desc->token;
	exp.handler_set = (sess->desc->handler != NULL) ? 1 : 0;
	spin_unlock_bh(&sess->lock);

	if (copy_to_iter(&exp, sizeof(exp), &msg->msg_iter) != sizeof(exp))
		return -EFAULT;

	return sizeof(exp);
}

