int psmgr_release(struct socket *sock)
{
	struct sock *sk = sock->sk;
	struct psmgr_sock *psk;
	struct psmgr_session *sess;
	struct psmgr_net *pn;

	if (!sk)
		return 0;

	psk  = psmgr_sk(sk);
	sess = psk->session;

	if (sess) {
		pn = psmgr_net(sock_net(sk));

