static int __init psmgr_init(void)
{
	int ret;

	/* Verify the processing descriptor layout matches the wire format. */
	BUILD_BUG_ON(sizeof(struct psmgr_desc) != PSMGR_BUF_TOTAL_SZ);
	BUILD_BUG_ON(offsetof(struct psmgr_desc, write_count) != PSMGR_BUF_DATA_SZ);
	BUILD_BUG_ON(offsetof(struct psmgr_desc, token) != PSMGR_BUF_DATA_SZ + 4);
	BUILD_BUG_ON(offsetof(struct psmgr_desc, handler)    != PSMGR_BUF_DATA_SZ + 8);

	ret = register_pernet_subsys(&psmgr_net_ops);
	if (ret) {
		pr_err("psmgr: register_pernet_subsys failed: %d\n", ret);
		return ret;
	}

	ret = proto_register(&psmgr_proto, 1);
	if (ret) {
		pr_err("psmgr: proto_register failed: %d\n", ret);
		goto err_pernet;
	}

	ret = sock_register(&psmgr_family);
	if (ret) {
		pr_err("psmgr: sock_register failed: %d\n", ret);
		goto err_proto;
	}

	if (!proc_create_net("psmgr_table", 0444, init_net.proc_net,
						 &psmgr_seq_ops, sizeof(struct net *))) {
		pr_err("psmgr: proc_create_net failed\n");
		ret = -ENOMEM;
		goto err_sock;
	}

	pr_info("psmgr: AF_PSMGR (%d) registered\n", AF_PSMGR);
	return 0;

err_sock:
	sock_unregister(AF_PSMGR);
err_proto:
	proto_unregister(&psmgr_proto);
err_pernet:
	unregister_pernet_subsys(&psmgr_net_ops);
	return ret;
}

static void __exit psmgr_exit(void)
{
	remove_proc_entry("psmgr_table", init_net.proc_net);
	sock_unregister(AF_PSMGR);
	proto_unregister(&psmgr_proto);
	unregister_pernet_subsys(&psmgr_net_ops);
	pr_info("psmgr: unloaded\n");
}

module_init(psmgr_init);
module_exit(psmgr_exit);

